 1	import * as React from 'react';
 2	import * as fuzzy from 'fuzzysearch';
 3	import { useTranslation } from 'react-i18next';
 4	import {
 5	  K8sResourceKind,
 6	  RedExclamationCircleIcon,
 7	  useActiveNamespace,
 8	  useK8sWatchResource,
 9	} from '@openshift-console/dynamic-plugin-sdk';
10	import { useField, useFormikContext, FormikValues } from 'formik';
11	import cx from 'classnames';
12	import { PersistentVolumeClaimModel } from '../../models';
13	import ResourceDropdown from './ResourceDropdown';
14	import {
15	  FormGroup,
16	  FormHelperText,
17	  HelperText,
18	  HelperTextItem,
19	} from '@patternfly/react-core';
20	import { getFieldId } from '../pipelines-details/multi-column-field/utils';
21	import { useFormikValidationFix } from '../pipelines-details/multi-column-field/formik-validation-fix';
22	import './PVCDropdown.scss';
23	
24	interface PVCDropdownProps {
25	  name: string;
26	}
27	
28	const PVCDropdown: React.FC<PVCDropdownProps> = ({ name }) => {
29	  const { t } = useTranslation('plugin__pipelines-console-plugin');
30	  const [field, { touched, error }] = useField(name);
31	  const { setFieldValue, setFieldTouched } = useFormikContext<FormikValues>();
32	  const fieldId = getFieldId(name, 'ns-dropdown');
33	  const isValid = !(touched && error);
34	  const errorMessage = !isValid ? error : '';
35	
36	  useFormikValidationFix(field.value);
37	  const [namespace] = useActiveNamespace();
38	  const autocompleteFilter = (strText, item): boolean =>
39	    fuzzy(strText, item?.props?.name);
40	  const resource = {
41	    isList: true,
42	    kind: PersistentVolumeClaimModel.kind,
43	    namespace,
44	    optional: true,
45	  };
46	  const [resources, loaded, loadError] = useK8sWatchResource(resource);
47	  return (
48	    <>
49	      <FormGroup fieldId={fieldId} isRequired data-test="pvc-dropdown">
50	        <ResourceDropdown
51	          resources={[
52	            {
53	              kind: PersistentVolumeClaimModel.kind,
54	              loaded,
55	              loadError,
56	              data: resources as K8sResourceKind[],
57	            },
58	          ]}
59	          loaded={loaded}
60	          loadError={loadError}
61	          dataSelector={['metadata', 'name']}
62	          selectedKey={field.value}
63	          placeholder={t('Select a PVC')}
64	          autocompleteFilter={autocompleteFilter}
65	          dropDownClassName={cx({ 'dropdown--full-width': true })}
66	          onChange={(value: string) => {
67	            setFieldValue(name, value);
68	            setFieldTouched(name, true);
69	          }}
70	          showBadge
71	        />
72	        <FormHelperText>
73	          <HelperText>
74	            {!isValid && (
75	              <HelperTextItem
76	                variant="error"
77	                icon={<RedExclamationCircleIcon />}
78	              >
79	                {errorMessage}
80	              </HelperTextItem>
81	            )}
82	          </HelperText>
83	        </FormHelperText>
84	      </FormGroup>
85	    </>
86	  );
87	};
88	
89	export default PVCDropdown;

